const PADDING = 25;
const SCALE   = 2.6;
const HALO_EXT = 260;

// ── COMPUTED BOUNDS ──────────────────────────────────────────────────────────
// The original D.w / D.h hard-coded a viewbox that cropped the southern edge.
// Walk every geometry layer once to derive a true min/max envelope so the full
// site (including buffer, water tail, social pocket, splays) is always visible.
function computeBounds() {
  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
  const eat = (pts) => {
    if (!Array.isArray(pts)) return;
    for (const pt of pts) {
      if (!Array.isArray(pt) || pt.length < 2) continue;
      const x = pt[0], y = pt[1];
      if (typeof x !== 'number' || typeof y !== 'number') continue;
      if (x < minX) minX = x;  if (y < minY) minY = y;
      if (x > maxX) maxX = x;  if (y > maxY) maxY = y;
    }
  };
  const eatGroup = (group) => {
    if (!Array.isArray(group)) return;
    for (const poly of group) eat(poly);
  };
  if (Array.isArray(D.plots)) D.plots.forEach(p => p && eat(p.p));
  eatGroup(D.water);
  eatGroup(D.buffer);
  eatGroup(D.roads);
  eatGroup(D.green);
  eatGroup(D.social);
  eatGroup(D.utility);
  eatGroup(D.boundary);
  eatGroup(D.splay);
  if (!isFinite(minX)) { minX = 0; minY = 0; maxX = D.w || 230; maxY = D.h || 470; }
  return { minX, minY, maxX, maxY };
}
const BOUNDS = computeBounds();
const SITE_W = BOUNDS.maxX - BOUNDS.minX;
const SITE_H = BOUNDS.maxY - BOUNDS.minY;

// World-to-canvas projector (handles negative coordinates in the data).
function ptsToPath(pts) {
  return pts.map(([x, y]) =>
    `${(x - BOUNDS.minX) * SCALE + PADDING},${(y - BOUNDS.minY) * SCALE + PADDING}`
  ).join(' ');
}
// Single-point projector.
function proj(x, y) {
  return [(x - BOUNDS.minX) * SCALE + PADDING, (y - BOUNDS.minY) * SCALE + PADDING];
}

// Proper polygon centroid via the shoelace / signed-area formula.
// Falls back to vertex average for degenerate polygons (area ≈ 0).
function centroid(pts) {
  if (!pts || pts.length < 3) {
    let sx = 0, sy = 0;
    for (const [x, y] of (pts || [])) { sx += x; sy += y; }
    const n = (pts && pts.length) || 1;
    return [sx / n, sy / n];
  }
  let area = 0, cx = 0, cy = 0;
  const n = pts.length;
  for (let i = 0; i < n; i++) {
    const [x0, y0] = pts[i];
    const [x1, y1] = pts[(i + 1) % n];
    const cross = x0 * y1 - x1 * y0;
    area += cross;
    cx   += (x0 + x1) * cross;
    cy   += (y0 + y1) * cross;
  }
  area *= 0.5;
  if (Math.abs(area) < 1e-6) {
    let sx = 0, sy = 0;
    for (const [x, y] of pts) { sx += x; sy += y; }
    return [sx / n, sy / n];
  }
  return [cx / (6 * area), cy / (6 * area)];
}

